import Graph from './Graph';
import DataDisplayChange from './DataDisplayChange';
import dataStore from 'app/stores/sensors/dataStore';
import annotationPlugin from 'chartjs-plugin-annotation';
import {Chart as ChartJS} from 'chart.js/auto';
ChartJS.register(annotationPlugin);
import 'chartjs-adapter-date-fns';
import {getDeviceName} from './Graph';
import AnnotationModal from './AnnotationModal';
import dayjs from 'dayjs';

const {datetimeUiFormat, datetimeApiFormat, dateUiFormat, dateApiFormat, monthDateUiFormat, yearFormat} = __.app;
let {i18n} = __;
let isMouseOverTooltip = false;
let isTooltipActive = false;

class VisualizationGraph extends Graph {
  /**
   * Compute the config needed for highcharts to display graph
   */
  // TODO: refacto function to simplify it
  // eslint-disable-next-line complexity, max-statements

  constructor(props) {
    super(props);

    this.state = {
      ...this.state,
      showModal: false,
      clickedData: null,
    };

    this.onDataClick = this.onDataClick.bind(this);
    this.closeModal = this.closeModal.bind(this);
    this.handleMouseLeaveChartBox = this.handleMouseLeaveChartBox.bind(this);
  }

  componentDidMount() {
    const chartBox = document.querySelector('.chart-box');
    if (chartBox) {
      chartBox.addEventListener('mouseleave', this.handleMouseLeaveChartBox);
    }
  }

  componentWillUnmount() {
    const chartBox = document.querySelector('.chart-box');
    if (chartBox) {
      chartBox.removeEventListener('mouseleave', this.handleMouseLeaveChartBox);
    }
  }

  handleMouseLeaveChartBox() {
    if (!isMouseOverTooltip) {
      this.hideTooltip();
    }
  }

  externalTooltipHandler(context) {
    const {chart, tooltip} = context;
    const tooltipEl = this.getOrCreateTooltip(chart);

    if (tooltip.opacity === 0 && !isMouseOverTooltip) {
      if (isTooltipActive) {
        this.hideTooltip();
      }
      return;
    }

    // Display the tooltip
    if (tooltip.body) {
      const titleLines = tooltip.title || [];
      const bodyLines = tooltip.body.map((b) => b.lines);

      const tableHead = document.createElement('thead');
      titleLines.forEach((title) => {
        const tr = document.createElement('tr');
        const th = document.createElement('th');
        const text = document.createTextNode(title);

        th.appendChild(text);
        tr.appendChild(th);
        tableHead.appendChild(tr);
      });

      const tableBody = document.createElement('tbody');
      bodyLines.forEach((body) => {
        const tr = document.createElement('tr');
        const td = document.createElement('td');
        const text = document.createTextNode(body);

        td.appendChild(text);
        tr.appendChild(td);
        tableBody.appendChild(tr);
      });

      // Retrieve the first annotation's message
      const dataPoints = context.chart.tooltip.dataPoints;
      const hasSensorId = dataPoints && dataPoints[0]?.dataset?.sensorId;

      if (hasSensorId) {
        const dataIndex = dataPoints[0]?.dataIndex;
        const datasetIndex = dataPoints[0]?.datasetIndex;
        const annotations = this.props.dataToDisplay[datasetIndex - 1]?.formattedData[dataIndex]?.annotations;

        const firstAnnotationMessage = annotations?.[Object.keys(annotations)[0]]?.[0]?.message || '';

        // Compute the width available for the message
        const tooltipParentWidth = chart.canvas.parentNode.offsetWidth;
        const tooltipWidth = Math.min(tooltipParentWidth * 0.15);

        // Add the comment to the tooltip
        if (firstAnnotationMessage) {
          const trComment = document.createElement('tr');
          const tdComment = document.createElement('td');
          const commentText = document.createTextNode(
            `${i18n.t('VisualizationGraph.tooltip.comment')} ${firstAnnotationMessage}`,
          );

          tdComment.appendChild(commentText);
          tdComment.style.whiteSpace = 'nowrap';
          tdComment.style.overflow = 'hidden';
          tdComment.style.textOverflow = 'ellipsis';
          tdComment.style.maxWidth = `${tooltipWidth}px`;

          trComment.appendChild(tdComment);
          tableBody.appendChild(trComment);
        }
      }

      const tableRoot = tooltipEl.querySelector('table');
      while (tableRoot.firstChild) {
        tableRoot.firstChild.remove();
      }
      tableRoot.appendChild(tableHead);
      tableRoot.appendChild(tableBody);

      // Update the tooltip border color
      const borderColor = tooltip.labelColors[0].borderColor;
      tooltipEl.style.borderColor = borderColor;
    }

    // Position the tooltip
    const {offsetLeft: positionX, offsetTop: positionY} = chart.canvas;
    tooltipEl.style.opacity = 1;
    tooltipEl.style.left = positionX + tooltip.caretX + 'px';
    tooltipEl.style.top = positionY + tooltip.caretY + 'px';
    tooltipEl.style.font = tooltip.options.bodyFont.string;
    tooltipEl.style.padding = `${tooltip.options.padding}px ${tooltip.options.padding}px`;

    isTooltipActive = true;

    // Check for presence of dataPoints and sensorId
    const dataPoints = context.chart.tooltip.dataPoints;
    const hasSensorId = dataPoints && dataPoints[0]?.dataset?.sensorId;

    // Remove the old button on each new interaction
    let buttonContainer = tooltipEl.querySelector('.button-container');
    if (buttonContainer) {
      buttonContainer.remove();
    }

    // If a sensorId is present, the button is displayed
    if (hasSensorId) {
      const dataIndex = dataPoints[0].dataIndex;
      const backgroundColor = dataPoints[0].dataset.backgroundColor;

      // Check if the value at dataIndex in backgroundColor is CanvasPattern
      const isAnnotated = backgroundColor[dataIndex] instanceof CanvasPattern;

      // Create and add the container for the button
      const btnContainerDiv = document.createElement('div');
      btnContainerDiv.classList.add('button-container');
      btnContainerDiv.style.display = 'flex';
      btnContainerDiv.style.justifyContent = 'center';
      btnContainerDiv.style.marginTop = '5px';

      // Creating the button with inline styles
      const button = document.createElement('button');
      button.innerText = isAnnotated
        ? i18n.t('VisualizationGraph.tooltipButton.displayComment')
        : i18n.t('VisualizationGraph.tooltipButton.addComment');
      button.style.backgroundColor = '#4caf50';
      button.style.color = 'white';
      button.style.paddingTop = '0.25rem';
      button.style.paddingBottom = '0.25rem';
      button.style.paddingLeft = '0.5rem';
      button.style.paddingRight = '0.5rem';
      button.style.borderRadius = '0.25rem';
      button.style.cursor = 'pointer';
      button.style.border = 'none';

      // Style for hover and active
      button.onmouseover = function () {
        button.style.backgroundColor = '#358438';
      };
      button.onmouseout = function () {
        button.style.backgroundColor = '#4caf50';
      };
      button.onmousedown = function () {
        button.style.backgroundColor = '#2d6830';
      };
      button.onmouseup = function () {
        button.style.backgroundColor = '#358438';
      };

      // Add click event
      button.addEventListener('click', () => {
        const config = chart.config._config;
        this.handleClickOnData(dataPoints, config);
      });

      // Append the button to the container
      btnContainerDiv.appendChild(button);
      tooltipEl.appendChild(btnContainerDiv);
    }
  }

  getOrCreateTooltip(chart) {
    let tooltipEl = chart.canvas.parentNode.querySelector('div');

    if (!tooltipEl) {
      tooltipEl = document.createElement('div');
      tooltipEl.classList.add('custom-tooltip');

      const table = document.createElement('table');
      table.style.margin = '0px';

      const arrowEl = document.createElement('div');
      arrowEl.classList.add('tooltip-arrow');

      // Add table and arrow to the tooltip
      tooltipEl.appendChild(table);
      tooltipEl.appendChild(arrowEl);

      // Add tooltip to the DOM of the canvas
      chart.canvas.parentNode.appendChild(tooltipEl);

      tooltipEl.addEventListener('mouseenter', () => {
        isMouseOverTooltip = true;
        tooltipEl.style.opacity = 1;
      });

      tooltipEl.addEventListener('mouseleave', () => {
        isMouseOverTooltip = false;
        this.hideTooltip();
      });

      tooltipEl.addEventListener('transitionend', (event) => {
        if (event.propertyName === 'opacity' && tooltipEl.style.opacity === '0') {
          tooltipEl.remove();
        }
      });
    }

    return tooltipEl;
  }

  hideTooltip() {
    const tooltipEl = document.querySelector('.custom-tooltip');
    if (tooltipEl) {
      tooltipEl.style.opacity = 0;
    }
    isTooltipActive = false;
  }

  handleClickOnData(dataPoints, config) {
    // Check if there are clicked elements
    if (dataPoints.length > 0) {
      const dataPosition = dataPoints[0].dataIndex; // Get the position of the clicked data point
      let elementDatasetIndex = dataPoints[0].datasetIndex; // Get the dataset index of the clicked element
      // Verify if the dataset contains a sensorId
      const clickedSensorId = dataPoints[0].dataset.sensorId;

      if (clickedSensorId) {
        const {groupBy, dataToDisplay} = this.props;

        let firstDatasetLabelName = config.data.datasets[0].label;

        if (firstDatasetLabelName.includes(i18n.t('VisualizationGraph.legend.addedComment'))) {
          // elementDatasetIndex - 1 because the first dataset is the annotationLegend
          elementDatasetIndex -= 1;
        }

        const annotations = dataToDisplay[elementDatasetIndex].formattedData[dataPosition].annotations;

        // Retrieve the date from the array of labels
        const dateFromArray = config.data.labels[dataPosition][0];

        let dateUiFormatAnnotations;
        let dateApiFormatAnnotations;

        // Adjust date formats based on the groupBy value
        switch (groupBy) {
          case 'default':
          case 'hour':
            dateUiFormatAnnotations = datetimeUiFormat;
            dateApiFormatAnnotations = datetimeApiFormat;
            break;
          case 'day':
            dateUiFormatAnnotations = dateUiFormat;
            dateApiFormatAnnotations = dateApiFormat;
            break;
          case 'month':
            dateUiFormatAnnotations = monthDateUiFormat;
            dateApiFormatAnnotations = 'YYYY-MM-01T00:00:00';
            break;
          case 'year':
            dateUiFormatAnnotations = yearFormat;
            dateApiFormatAnnotations = 'YYYY-01-01T00:00:00';
            break;
          default:
            return;
        }

        // Format the clicked date into API format
        const clickedDateApi = dayjs(dateFromArray, dateUiFormatAnnotations).format(dateApiFormatAnnotations);

        // Call the onDataClick method with all relevant information
        this.onDataClick({
          clickedSensorId,
          clickedDate: clickedDateApi,
          clickedDateUi: dateFromArray,
          groupBy,
          annotations,
          dataPosition,
          elementDatasetIndex,
        });
      }
    }
  }

  onDataClick(clickedData) {
    this.setState({
      showModal: true,
      clickedData: clickedData,
    });
  }

  closeModal() {
    this.setState({
      showModal: false,
    });
  }

  computeConfig() {
    let {objToDisplay, displayDataQuantError, isObjectiveDisplayed} = this.state;
    let {groupBy, mainSensor, refObjective, displayedValue, displayedValueComputeBy} = this.props;
    let dataToDisplay = this.props.dataToDisplay;
    let mainDataType = mainSensor ? this.getDataType(mainSensor.dataTypeId) : null;
    let nbSensors = _.uniqBy(dataToDisplay, 'sensorId').length;
    let config = {
      data: {
        labels: this.props.categories,
        datasets: [],
      },
      options: {
        scales: {},
        plugins: {
          annotation: {},
        },
        responsive: true,
        maintainAspectRatio: false,
        onClick: (event, elements) => {
          if (elements.length > 0) {
            const elementIndex = elements[0].index;
            const datasetIndex = elements[0].datasetIndex;
            const dataPointValue = config.data.datasets[datasetIndex].data[elementIndex];

            let dataValue = 0;
            if (typeof dataPointValue === 'number') {
              if (dataPointValue < 0.01) {
                dataValue = parseFloat(dataPointValue.toFixed(3));
              } else {
                dataValue = parseFloat(dataPointValue.toFixed(2));
              }
            }

            _.copyToClipboard(dataValue, i18n.t('VisualizationGraph.dataCopiedValue', {value: dataValue}));
          }
        },
        onHover: (event, elements) => {
          const chartCanvas = event.native.target;
          if (elements.length > 0) {
            // When hovering a data point
            chartCanvas.style.cursor = 'pointer';
          } else {
            // When not hovering a data point
            chartCanvas.style.cursor = 'default';
          }
        },
      },
    };

    ChartJS.defaults.datasets.line.pointHitRadius = 8;

    // If group by is default, xAxis is based on datetime else on categories

    if (groupBy !== 'default') {
      config.options.scales.x = {
        offset: true,
        type: 'category',
        grid: {
          display: false,
        },
        ticks: {
          padding: 10,
        },
      };
    } else {
      config.options.scales.x = {
        offset: true,
        grid: {
          display: false,
        },
      };
    }

    /*------------------------------------------------------------------------*\
          Config for raw data
        \*------------------------------------------------------------------------*/
    let uniqueSensorIndex = 0;
    let uniqueDJUIndex = 0;
    let yAxis = [];
    for (let key in dataToDisplay) {
      let datum = dataToDisplay[key];

      // Format each data based on the groupBy value
      let data = [];

      if (groupBy === 'default') {
        data = datum.formattedData.map((d) => {
          let temp = d.value;
          return temp;
        });
      } else {
        data = datum.formattedData.map((d) => {
          let temp = d.value;
          return temp;
        });
      }
      let yIndex = null;
      let dataType = this.getDataType(dataToDisplay[key].dataTypeId);
      let unitAxis = this.getUnitAxis({
        unit: dataType.unit,
        isAverage: dataType.isAverage,
      });
      let yAxisAvailable = yAxis.filter((axis) => {
        return axis.unit === unitAxis;
      });

      if (yAxisAvailable.length > 0) {
        yIndex = yAxis.indexOf(yAxisAvailable[0]);
      } else {
        let legendName = i18n.t('store.dataTypes.name.' + dataType.name, {
          defaultValue: dataType.name,
        });

        if (this.props.displayedValue === 'money' && !dataType.isAverage) {
          legendName = i18n.t('Reporting.money');
        } else if (this.props.displayedValue === 'co2') {
          legendName = 'co2';
        }

        // Manage objective display on the graph
        let value = this._formatObjDataQuantity(groupBy, objToDisplay.quantity, objToDisplay.duration);

        yAxis.push({
          grace: '18%',
          beginAtZero: true,
          title: {
            display: true,
            text: legendName,
            color: dataToDisplay[key].config.color,
            padding: 20,
          },
          ticks: {
            callback: (v) => parseFloat(v.toFixed(1)) + ' ' + unitAxis,
            count: 11,
            align: 'start',
          },
          match: {
            type: 'linear',
            ticks: {
              count: (context) => {
                return context.chart.options.scales[`y-axis-${i}`].ticks.count;
              },
            },
          },
          unit: unitAxis,
          position: yAxis.length > 0 ? 'right' : 'left',
        });

        yIndex = yAxis.length - 1;

        // Extract the keys of the 'yAxis' object and store them in an array
        const yAxisKeys = Object.keys(yAxis);

        // Loop through the 'yAxisKeys' array to assign yAxis configurations to the chart's 'config' object
        for (let i = 0; i < yAxisKeys.length; i++) {
          // Get the current property (yAxiskey) from the 'yAxisKeys' array
          const prop = yAxisKeys[i];
          // Associate the configuration of the current yAxis with the corresponding 'y-axis-${i}' property key
          config.options.scales[`y-axis-${i}`] = yAxis[prop];
        }

        // Configuration of the tooltip
        config.options.plugins.tooltip = {
          enabled: false,
          position: 'average',
          external: this.externalTooltipHandler.bind(this),
          yAlign: 'bottom',
          displayColors: false,
          titleColor: 'black',
          bodyColor: 'black',
          backgroundColor: 'rgba(206, 206, 206, .8)',
          borderWidth: 2,
          borderColor: (tooltipItem) => {
            // Function to get the tooltip border color
            if (tooltipItem.tooltipItems[0]) {
              // Set the tooltip border color to match the backgroundColor of the first tooltip item's dataset
              return tooltipItem.tooltipItems[0].dataset.borderColor;
            }
          },
          callbacks: {
            title: function (tooltipItems) {
              let datesDisplay = [];

              tooltipItems.forEach(function (tooltipItem) {
                // Retrieve the dataset and its properties for the current tooltip item
                const datasetIndex = tooltipItem.datasetIndex;
                const dataset = config.data.datasets[datasetIndex];
                const datasetLabel = dataset.label;
                const dataIsDJU = dataset.dju;
                const kwhLinkedTo = dataset.uniqueSensorIndex;
                const label = tooltipItem.label;
                const dates = label.split(',');

                // Check if the dataset label is for 'Objectifs' and push the first date to display
                if (datasetLabel.startsWith(i18n.t('Dashboard.objectiveTitle'))) {
                  datesDisplay.push(dates.length > 0 ? dates[0].trim() : ' ');
                }
                // Check if the dataset label is for 'DJU' and directly access the date using uniqueDJUIndex
                else if (dataIsDJU) {
                  if (dates[kwhLinkedTo] != null) {
                    datesDisplay.push(dates[kwhLinkedTo].trim());
                  }
                }
                // If the label includes 'Threshold', find the dataset index for the non-threshold data preceding it
                else if (datasetLabel.includes(i18n.t('VisualizationGraph.threshold'))) {
                  // Find the index of the dataset that is just before the first 'Threshold' dataset
                  let dataIndexForThresholds = datasetIndex - 1;
                  while (
                    dataIndexForThresholds > 0 &&
                    config.data.datasets[dataIndexForThresholds].label.includes(i18n.t('VisualizationGraph.threshold'))
                  ) {
                    dataIndexForThresholds--;
                  }
                  // Verify and retrieve the corresponding date
                  if (dataIndexForThresholds >= 0 && dates[dataIndexForThresholds] != null) {
                    datesDisplay.push(dates[dataIndexForThresholds].trim());
                  }
                }
                // For normal sensor datasets, use the uniqueSensorIndex to find the corresponding date
                else {
                  const dataUniqueSensorIndex = dataset.uniqueSensorIndex;
                  if (dates[dataUniqueSensorIndex] != null) {
                    datesDisplay.push(dates[dataUniqueSensorIndex].trim());
                  }
                }
              });

              // Join all dates and return as a single string to display in the tooltip
              return datesDisplay.join(' | ');
            },
            // Define custom tooltip label rendering
            label: function (tooltipItem, data) {
              // Get the label name of the first dataset
              const firstDatasetLabelName = config.data.datasets[0].label;
              // Get the label name and value based on the dataset index and tooltip index
              const labelName = config.data.datasets[tooltipItem.datasetIndex].label;
              const dataPoint = config.data.datasets[tooltipItem.datasetIndex].data[tooltipItem.dataIndex];
              const dataValue =
                typeof dataPoint === 'number'
                  ? dataPoint < 0.01
                    ? parseFloat(dataPoint.toFixed(3))
                    : parseFloat(dataPoint.toFixed(2))
                  : 0;
              // Determine the unit for the tooltip based on the labelName
              const unitAxe = labelName.startsWith(i18n.t('Dashboard.objectiveTitle'))
                ? firstDatasetLabelName.includes(i18n.t('VisualizationGraph.legend.addedComment'))
                  ? config.data.datasets[1].unit
                  : config.data.datasets[0].unit
                : config.data.datasets[tooltipItem.datasetIndex].unit;
              // Create the tooltip label string with the label name, value, and unit
              const labelString = `${labelName} : ${dataValue} ${unitAxe}`;
              return labelString;
            },
          },
        };
      }

      if (key === 0 && this.props.displayedValue === 'energy') {
        let refObjSerie = this.computeRefObjSerie();
        config.data.datasets.push(refObjSerie);
      }

      const hasAnnotations = (d) =>
        d.annotations && typeof d.annotations === 'object' && Object.keys(d.annotations).length > 0;

      // If annotations are present, adds an `annotationLegend` object to `datasets`.
      // This object is configured to remain invisible on the chart but uses a background pattern
      // (borderColor) to appear in the legend
      if (
        datum.formattedData.some(hasAnnotations) &&
        !config.data.datasets.some((dataset) =>
          dataset.label?.includes(i18n.t('VisualizationGraph.legend.addedComment')),
        )
      ) {
        let annotationLegend = {
          label: i18n.t('VisualizationGraph.legend.addedComment'),
          type: 'line',
          data: Array(data.length).fill(null), // Only null data points to not appear on the graph
          borderColor: this.createPattern('black'), // Black pattern to show in legend
          pointRadius: 0, // Invisible points
          hoverRadius: 0, // No hover radius
        };

        // Push the annotation into datasets
        config.data.datasets.unshift(annotationLegend);
      }

      // Create the serie object and associate it to the right yAxis
      let serie = {
        yAxisID: `y-axis-${yIndex}`,
        unit: unitAxis,
        label: datum.sensorId ? getDeviceName(datum.sensorId, 'sensor') : getDeviceName(datum.meterId, 'meter'),
        type: datum.config.graphType,
        data: data,
        borderColor: datum.config.color,

        // Define borderWidth based on the graph type and annotations
        borderWidth: datum.formattedData.map((d) => {
          return datum.config.graphType === 'bar' ? (hasAnnotations(d) ? 2 : 0) : 3;
        }),

        // Define backgroundColor based on annotations
        backgroundColor: datum.formattedData.map((d) => {
          return hasAnnotations(d) ? this.createPattern(datum.config.color) : datum.config.color;
        }),

        // Define pointRadius based on annotations
        pointRadius: datum.formattedData.map((d) => (hasAnnotations(d) ? 8 : 2)),

        // Define hoverRadius based on annotations
        hoverRadius: datum.formattedData.map((d) => (hasAnnotations(d) ? 10 : 4)),

        // Define hoverBorderWidth based on annotations
        hoverBorderWidth: datum.formattedData.map((d) => (hasAnnotations(d) ? 3 : 1)),

        // Set the order based on graph type
        order: datum.config.graphType === 'line' ? -1 : 2,

        uniqueSensorIndex: uniqueSensorIndex++,
        sensorId: datum.sensorId,
      };

      config.data.datasets.push(serie);

      // Check if thresholds are defined, if groupBy is not 'default'
      // and if displayedValueComputeBy is not true, and groupBy
      if (
        dataToDisplay[key].thresholds &&
        groupBy !== 'default' &&
        !displayedValueComputeBy &&
        displayedValue === 'value' &&
        nbSensors === 1
      ) {
        let thresholdCriticalValue, thresholdAvgValue;

        // Extract dateBegin and dateEnd from the data configuration
        const {dateBegin, dateEnd} = dataToDisplay[key].config;

        // Determine if the data represents an average value
        let isAverage = dataToDisplay[key].isAverage;

        // Calculate the critical and average threshold values based on the groupBy setting, isAverage flag,
        // and the date range from dateBegin to dateEnd
        if (dataToDisplay[key].thresholds.critical) {
          thresholdCriticalValue = this.calculateThresholdValues(
            dataToDisplay[key].thresholds.critical.value,
            groupBy,
            isAverage,
            dateBegin.format(dateApiFormat),
            dateEnd.format(dateApiFormat),
          );
        }

        if (dataToDisplay[key].thresholds.avg) {
          thresholdAvgValue = this.calculateThresholdValues(
            dataToDisplay[key].thresholds.avg.value,
            groupBy,
            isAverage,
            dateBegin.format(dateApiFormat),
            dateEnd.format(dateApiFormat),
          );
        }

        // Check if the thresholds have already been added to the chart to avoid duplication
        let thresholdsAdded = config.data.datasets.some(
          (dataset) =>
            dataset.label?.includes(i18n.t('VisualizationGraph.criticalThreshold')) ||
            dataset.label?.includes(i18n.t('VisualizationGraph.averageThreshold')),
        );

        // Proceed with adding threshold series to the chart if they haven't been added yet
        if (!thresholdsAdded) {
          let thresholdCriticalData, thresholdAvgData;

          // Use the calculated threshold values directly for groupBy 'month' and 'year'
          // For others, fill an array with the calculated threshold value
          if (groupBy === 'month' || groupBy === 'year') {
            thresholdCriticalData = thresholdCriticalValue || [];
            thresholdAvgData = thresholdAvgValue || [];
          } else {
            // Create two array filled with the critical and average threshold value for each data point
            const dataLength = dataToDisplay[key].formattedData.length;
            thresholdCriticalData = thresholdCriticalValue
              ? new Array(dataLength).fill(thresholdCriticalValue[0] || thresholdCriticalValue)
              : [];
            thresholdAvgData = thresholdAvgValue
              ? new Array(dataLength).fill(thresholdAvgValue[0] || thresholdAvgValue)
              : [];
          }

          // Configure the data series for the critical threshold
          if (thresholdCriticalValue) {
            let thresholdCriticalSerie = {
              yAxisID: `y-axis-${yIndex}`,
              label: `${i18n.t('VisualizationGraph.criticalThreshold')} - ${getDeviceName(datum.sensorId, 'sensor')}`,
              type: 'line',
              data: thresholdCriticalData,
              borderColor: dataToDisplay[key].thresholds.critical.color,
              backgroundColor: dataToDisplay[key].thresholds.critical.color,
              borderDash: [10, 1],
              unit: unitAxis,
              pointRadius: 2,
              pointHitRadius: 10,
              borderWidth: 1,
              order: -1,
            };
            // Add the configured critical threshold series to the chart's dataset
            config.data.datasets.push(thresholdCriticalSerie);
          }

          if (thresholdAvgValue) {
            // Configure the data series for the average threshold
            let thresholdAvgSerie = {
              yAxisID: `y-axis-${yIndex}`,
              label: `${i18n.t('VisualizationGraph.averageThreshold')} - ${getDeviceName(datum.sensorId, 'sensor')}`,
              type: 'line',
              data: thresholdAvgData,
              borderColor: dataToDisplay[key].thresholds.avg.color,
              backgroundColor: dataToDisplay[key].thresholds.avg.color,
              borderDash: [10, 1],
              unit: unitAxis,
              pointRadius: 2,
              pointHitRadius: 10,
              borderWidth: 1,
